template:
{{ define "titleTemplate" }}
  {{ if .Alerts.Firing -}} {{- /*문제 발생 시*/ -}}
    {{- if eq (len .Alerts.Firing) 1 -}} {{- /*1건일때*/ -}}
      {{ if .CommonLabels.alertname }} {{ .CommonLabels.alertname }} : {{ else }} {{ .CommonLabels.rulename }} : {{ end }}
      {{- range .CommonLabels.SortedPairs -}} {{- /*뒤에 시스템명 출력*/ -}}
          {{- if  (eq .Name "ServerName") -}} {{- .Value -}}
          {{- end -}}
      {{ end }}
    {{ else -}} {{- /*여러건일때*/ -}}
      {{ .CommonLabels.rulename }} : 경고 발생 {{ len .Alerts.Firing -}} 건
    {{- end -}}
  {{- end -}}
  {{ if .Alerts.Resolved -}} {{- /*문제 해소 시*/ -}}
    {{- if eq (len .Alerts.Resolved) 1 -}} {{- /*1건일때*/ -}}
      {{ if .CommonLabels.alertname }} {{ .CommonLabels.alertname }} : {{ else }} {{ .CommonLabels.rulename }} : {{ end }}
      {{- range .CommonLabels.SortedPairs -}} {{- /*뒤에 시스템명 출력*/ -}}
          {{- if  (eq .Name "ServerName") -}} {{- .Value -}}
          {{- end -}}
      {{ end }}
    {{ else -}} {{- /*여러건일때*/ -}}
      {{ .CommonLabels.rulename }} : 정상화 {{ len .Alerts.Resolved -}} 건
    {{- end -}}
  {{- end -}}
{{- end -}}
